int longestSubarray(int* nums, int numsSize, int k) {
    int freq[100001] = {0};
    int left = 0, repeated = 0, ans = 0;

    for (int right = 0; right < numsSize; right++) {
        freq[nums[right]]++;

        if (freq[nums[right]] == 2)
            repeated++;

        while (repeated > k) {
            freq[nums[left]]--;
            if (freq[nums[left]] == 1)
                repeated--;
            left++;
        }

        if (right - left + 1 > ans)
            ans = right - left + 1;
    }

    return ans;
}

