int trionic(int* nums, int n) {
    int* inc = (int*)malloc(sizeof(int) * n);
    int* dec = (int*)malloc(sizeof(int) * n);

    for (int i = 0; i < n; i++) {
        inc[i] = 1;
        dec[i] = 1;
    }

    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1])
            inc[i] = inc[i - 1] + 1;
    }

    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] > nums[i + 1])
            dec[i] = dec[i + 1] + 1;
    }

    int ans = 0;

    for (int i = 0; i < n; i++) {
        int len = inc[i] + dec[i] - 1;
        if (len > ans)
            ans = len;
    }

    free(inc);
    free(dec);

    return ans;
}

