int shortestSubarray(int* nums, int n) {
    int l = 0, r = n - 1;

    while (l < n - 1 && nums[l] <= nums[l + 1])
        l++;

    while (r > 0 && nums[r] >= nums[r - 1])
        r--;

    if (l >= r)
        return 0;

    int mn = INT_MAX, mx = INT_MIN;

    for (int i = l; i <= r; i++) {
        if (nums[i] < mn)
            mn = nums[i];
        if (nums[i] > mx)
            mx = nums[i];
    }

    while (l > 0 && nums[l - 1] > mn)
        l--;

    while (r < n - 1 && nums[r + 1] < mx)
        r++;

    return r - l + 1;
}

